/// <summary>
/// UnapproveChangeRequest — withdraws the caller's approval of an open-access request and revokes any grant
/// it produced, so the requester can no longer open the gated environment until re-approved.
/// </summary>
public sealed class UnapproveEndpoint(IEscOpenRequestStore requests, IAuditLog audit) : Endpoint<UnapproveRequest>
{
    public override void Configure()
    {
        Delete("/api/change-requests/{orgName}/{changeRequestID}/approve");
        AllowAnonymous();
        Description(b => b.WithTags("Organizations").WithSummary("UnapproveChangeRequest").WithName("Unapprove"));
    }

    public override async Task HandleAsync(UnapproveRequest req, CancellationToken ct)
    {
        var location = requests.Locate(req.OrgName, req.ChangeRequestId);
        if (location is null)
        {
            await Send.NotFoundAsync(ct);
            return;
        }

        var approver = User.Identity?.Name ?? "happypumi";
        var updated = location.Request with
        {
            Approvers = location.Request.ApproverList.Where(a => a != approver).ToList(),
            GrantExpiresAtUnix = 0, // withdrawing an approval revokes the grant
        };
        requests.Replace(location.Environment, updated);

        audit.Record(req.OrgName, "changeRequest.unapprove",
            $"Withdrew approval of open request '{req.ChangeRequestId}' for '{location.Environment.Project}/{location.Environment.Name}'", approver);
        await Send.NoContentAsync(ct);
    }
